            provider.stream_with_tools(vec![ChatMessage::user("tell me a joke")], vec![]);
        let mut last_done: Option<Usage> = None;
        while let Some(ev) = stream.next().await {
            if let StreamEvent::Done(usage) = ev {
                last_done = Some(usage);
