                },
                StreamEvent::Error(err) => panic!("unexpected stream error: {err}"),
                _ => {},
            }
        }

        assert!(saw_delta, "expected fallback stream to emit Delta");
        assert!(saw_done, "expected fallback stream to emit Done");
    }

