        let sse = concat!(
            "data: {\"choices\":[{\"delta\":{\"content\":\"hi\"},\"finish_reason\":null}]}\n\n",
            "data: {\"usage\":{\"prompt_tokens\":11,\"completion_tokens\":7}}\n\n",
