        .with_stream_transport(ProviderStreamTransport::Auto);

        let mut stream =
            provider.stream_with_tools(vec![ChatMessage::user("test")], sample_tools());

        let mut saw_delta = false;
        let mut saw_done = false;

        while let Some(event) = stream.next().await {
            match event {
